'use strict';
(function(){
const nav=document.querySelector('nav[aria-label="Browse mode"]');
if(!nav)return;
const links=nav.querySelectorAll(':scope > a');
nav.dataset.active=nav.querySelector(':scope > a:nth-child(2)[aria-current="page"]')?'end':'start';
for(const link of links){
link.addEventListener('click',()=>{
nav.dataset.active=link===links[links.length-1]?'end':'start';});}})();
(function(){
const checkbox=document.getElementById('uses-fuel');
const group=document.getElementById('fuel-type-group');
if(!checkbox||!group)return;
function toggle(){
group.hidden=!checkbox.checked;}
toggle();
checkbox.addEventListener('change',toggle);})();
(function(){
const slider=document.getElementById('filter-max-fee');
const display=document.getElementById('fee-display');
if(!slider||!display)return;
function syncSliderAria(){
display.textContent=`$${slider.value}`;
slider.setAttribute('aria-valuenow',slider.value);
slider.setAttribute('aria-valuetext',`$${slider.value}`);}
slider.addEventListener('input',syncSliderAria);})();
(function(){
const page=document.getElementById('browse-page');
if(!page)return;
const form=page.querySelector('form[role="search"]');
const grid=page.querySelector('[role="list"]');
const countArea=page.querySelector('[aria-live="polite"]');
const emptyState=page.querySelector('section[aria-label="No results"]');
if(!form)return;
form.noValidate=true;
const zipField=document.getElementById('filter-zip');
const radiusField=document.getElementById('filter-radius');
function syncZipRequired(){
if(!zipField||!radiusField)return;
zipField.required=radiusField.value!==''&&!(/^\d{5}$/).test(zipField.value);}
syncZipRequired();
radiusField?.addEventListener('change',syncZipRequired);
zipField?.addEventListener('input',syncZipRequired);
function getPaginationNav(){
return page.querySelector('nav[aria-label="Pagination"]');}
function getFilterFieldset(){
return form.querySelector('fieldset[aria-label="Filters"]');}
const DEBOUNCE_MS=300;
const SKELETON_COUNT=6;
const categorySelect=document.getElementById('filter-category');
const defaultCounts=new Map();
if(categorySelect){
for(const opt of categorySelect.options){
if(opt.value!=='')defaultCounts.set(opt.value,opt.textContent);}}
function updateCategoryCounts(counts){
if(!categorySelect)return;
for(const opt of categorySelect.options){
if(opt.value==='')continue;
if(counts){
const name=(defaultCounts.get(opt.value)??opt.textContent).replace(/\s*\(\d+\)\s*$/,'');
const n=counts[opt.value]??0;
opt.textContent=`${name} (${n})`;}else{
opt.textContent=defaultCounts.get(opt.value)??opt.textContent;}}}
let debounceTimer=null;
let abortCtrl=null;
let currentPage=1;
let isPaginating=false;
function getBasePath(){
return form.action?new URL(form.action).pathname:'/tools';}
function buildQueryString(){
const data=new FormData(form);
const params=new URLSearchParams();
for(const[key,value]of data){
if(key==='page')continue;
const trimmed=value.toString().trim();
if(trimmed!=='')params.set(key,trimmed);}
const slider=document.getElementById('filter-max-fee');
if(slider&&params.get('max_fee')===slider.max){
params.delete('max_fee');}
if(currentPage>1){
params.set('page',String(currentPage));}
return params;}
function hasActiveFilters(){
const params=buildQueryString();
params.delete('page');
return params.size>0;}
function showSkeletons(){
if(!grid)return;
grid.innerHTML='';
for(let i=0;i<SKELETON_COUNT;i++){
const card=document.createElement('div');
card.setAttribute('role','listitem');
card.setAttribute('aria-hidden','true');
card.className='skeleton-card';
grid.appendChild(card);}
if(emptyState)emptyState.hidden=true;}
function updateResultCount(data){
if(!countArea)return;
const existing=countArea.querySelector(':scope > p');
const p=document.createElement('p');
if(data.totalCount>0){
const strong1=document.createElement('strong');
strong1.textContent=`${data.rangeStart}–${data.rangeEnd}`;
const strong2=document.createElement('strong');
strong2.textContent=data.totalCount.toLocaleString();
const suffix=data.totalCount!==1?'tools':'tool';
p.append('Showing ',strong1,' of ',strong2,` ${suffix}`);}else{
p.textContent='No tools match your filters.';}
if(existing){
existing.replaceWith(p);}else{
countArea.prepend(p);}}
function updateClearButton(){
const fieldset=getFilterFieldset();
if(!fieldset)return;
const existing=fieldset.querySelector('a[data-intent="ghost"]');
const active=hasActiveFilters();
if(active&&!existing){
const basePath=getBasePath();
const link=document.createElement('a');
link.href=basePath;
link.setAttribute('role','button');
link.dataset.intent='ghost';
link.innerHTML='<i class="fa-solid fa-xmark" aria-hidden="true"></i> Clear Filters';
fieldset.appendChild(link);}else if(!active&&existing){
existing.remove();}}
async function fetchFiltered(replaceHistory=false){
clearTimeout(debounceTimer);
if(abortCtrl)abortCtrl.abort();
abortCtrl=new AbortController();
const params=buildQueryString();
const basePath=getBasePath();
const qs=params.toString();
const url=qs?`${basePath}?${qs}`:basePath;
showSkeletons();
try{
const res=await NT.fetch(url,{signal:abortCtrl.signal});
if(!res.ok){
form.submit();
return;}
const data=await res.json();
if(grid){
grid.innerHTML=data.html;}
const currentPagination=getPaginationNav();
if(currentPagination){
if(data.paginationHtml.trim()){
currentPagination.outerHTML=data.paginationHtml;}else{
currentPagination.remove();}}else if(data.paginationHtml.trim()&&grid){
grid.insertAdjacentHTML('afterend',data.paginationHtml);}
updateResultCount(data);
updateClearButton();
updateCategoryCounts(data.categoryCounts??null);
if(data.totalCount===0&&grid){
grid.innerHTML='';}
if(emptyState){
emptyState.hidden=data.totalCount>0;}
if(replaceHistory){
history.replaceState(null,'',url);}else{
history.pushState(null,'',url);}
if(isPaginating){
isPaginating=false;
window.scrollTo({top:0,behavior:'smooth'});}}catch(err){
if(err.name==='AbortError')return;
NT.toast('Something went wrong. Reloading\u2026','error');
form.submit();}}
function handleImmediateChange(){
clearTimeout(debounceTimer);
currentPage=1;
fetchFiltered();}
function handleDebouncedInput(){
clearTimeout(debounceTimer);
currentPage=1;
debounceTimer=setTimeout(fetchFiltered,DEBOUNCE_MS);}
form.addEventListener('submit',(e)=>{
e.preventDefault();
clearTimeout(debounceTimer);
currentPage=1;
fetchFiltered();});
const category=document.getElementById('filter-category');
category?.addEventListener('change',handleImmediateChange);
radiusField?.addEventListener('change',handleImmediateChange);
const search=document.getElementById('browse-search');
const maxFee=document.getElementById('filter-max-fee');
search?.addEventListener('input',handleDebouncedInput);
zipField?.addEventListener('input',handleDebouncedInput);
maxFee?.addEventListener('input',handleDebouncedInput);
page.addEventListener('click',(e)=>{
const link=e.target.closest('nav[aria-label="Pagination"] a');
if(!link)return;
e.preventDefault();
const linkUrl=new URL(link.href);
currentPage=parseInt(linkUrl.searchParams.get('page')??'1',10);
isPaginating=true;
fetchFiltered();});
page.addEventListener('click',(e)=>{
const clearLink=e.target.closest('fieldset a[data-intent="ghost"]');
if(!clearLink)return;
e.preventDefault();
form.reset();
syncZipRequired();
currentPage=1;
fetchFiltered();});
window.addEventListener('popstate',()=>{
const params=new URLSearchParams(window.location.search);
for(const el of form.elements){
if(!el.name||el.name==='page')continue;
const urlValue=params.get(el.name);
if(el.tagName==='SELECT'){
const option=urlValue!==null
?el.querySelector(`option[value="${CSS.escape(urlValue)}"]`)
:el.querySelector('option:first-child');
if(option)el.value=option.value;}else if(el.type!=='hidden'){
el.value=urlValue??el.defaultValue;}}
syncZipRequired();
currentPage=parseInt(params.get('page')??'1',10);
fetchFiltered(true);});
window.addEventListener('beforeunload',()=>{
clearTimeout(debounceTimer);
if(abortCtrl)abortCtrl.abort();});})();
(function(){
const page=document.getElementById('browse-page');
if(!page)return;
const grid=page.querySelector('[role="list"]');
const summary=page.querySelector('[aria-live="polite"]');
if(!grid||!summary)return;
const STORAGE_KEY='nt-view-preference';
const toolbar=document.createElement('div');
toolbar.setAttribute('data-view-toggle','');
toolbar.setAttribute('role','group');
toolbar.setAttribute('aria-label','View mode');
const gridBtn=document.createElement('button');
gridBtn.type='button';
gridBtn.innerHTML='<i class="fa-solid fa-grip" aria-hidden="true"></i>';
gridBtn.setAttribute('aria-label','Grid view');
gridBtn.title='Grid view';
gridBtn.dataset.view='grid';
const listBtn=document.createElement('button');
listBtn.type='button';
listBtn.innerHTML='<i class="fa-solid fa-list" aria-hidden="true"></i>';
listBtn.setAttribute('aria-label','List view');
listBtn.title='List view';
listBtn.dataset.view='list';
toolbar.append(gridBtn,listBtn);
summary.appendChild(toolbar);
const mql=window.matchMedia('(max-width: 600px)');
function setView(mode){
const effective=mql.matches?'grid':mode;
grid.dataset.view=effective;
gridBtn.setAttribute('aria-pressed',effective==='grid');
listBtn.setAttribute('aria-pressed',effective==='list');
if(!mql.matches)localStorage.setItem(STORAGE_KEY,mode);}
function getPreferred(){
return localStorage.getItem(STORAGE_KEY)==='list'?'list':'grid';}
setView(getPreferred());
mql.addEventListener('change',()=>setView(getPreferred()));
toolbar.addEventListener('click',(e)=>{
const btn=e.target.closest('button[data-view]');
if(!btn)return;
setView(btn.dataset.view);});})();
(function(){
const cropDialog=document.getElementById('crop-dialog');
const cropPreview=document.getElementById('crop-preview');
const cropViewport=document.getElementById('crop-viewport');
const cropFrame=document.getElementById('crop-frame');
const confirmBtn=cropDialog?.querySelector('[data-crop-confirm]');
const cancelBtn=cropDialog?.querySelector('[data-crop-cancel]');
const cropLabelEl=cropDialog?.querySelector('[data-crop-label]');
const confirmIcon=confirmBtn?.querySelector('i');
if(!cropDialog||!cropPreview||!cropViewport||!cropFrame)return;
let cropMode=null;
let cropFile=null;
let cropObjectUrl=null;
let cropFocalX=50;
let cropFocalY=50;
let repositionImageId=null;
let cropLayout=null;
let frameLeft=0;
let frameTop=0;
let savedScrollY=0;
let onConfirmCallback=null;
function clamp(val,min,max){
return Math.max(min,Math.min(max,val));}
function cleanupCropState(){
if(cropObjectUrl){
URL.revokeObjectURL(cropObjectUrl);
cropObjectUrl=null;}
cropFile=null;
cropMode=null;
cropLayout=null;
repositionImageId=null;
NT.style.removeRule('crop-preview');
NT.style.removeRule('crop-frame-size');
NT.style.removeRule('crop-frame-pos');
const fi=document.getElementById('add-photo')??document.getElementById('tool-photos');
if(fi)fi.value='';}
function closeCropDialog(){
cleanupCropState();
cropDialog.close();}
function layoutCrop(){
const stageW=cropViewport.clientWidth;
const stageH=cropViewport.clientHeight;
const natW=cropPreview.naturalWidth;
const natH=cropPreview.naturalHeight;
if(!natW||!natH)return;
const scale=Math.min(stageW/natW,stageH/natH);
const dispW=natW*scale;
const dispH=natH*scale;
const imgLeft=(stageW-dispW)/2;
const imgTop=(stageH-dispH)/2;
NT.style.setRule('crop-preview','#crop-preview',
`width:${dispW}px;height:${dispH}px;left:${imgLeft}px;top:${imgTop}px`);
let frameW,frameH;
if(dispW/dispH>1.5){
frameH=dispH;
frameW=dispH*1.5;}else{
frameW=dispW;
frameH=dispW/1.5;}
cropLayout={imgLeft,imgTop,dispW,dispH,frameW,frameH};
NT.style.setRule('crop-frame-size','#crop-frame',
`width:${frameW}px;height:${frameH}px`);
positionFrameFromFocal();}
function positionFrameFromFocal(){
if(!cropLayout)return;
const{imgLeft,imgTop,dispW,dispH,frameW,frameH}=cropLayout;
const maxOffsetX=dispW-frameW;
const maxOffsetY=dispH-frameH;
frameLeft=imgLeft+(maxOffsetX>0?(cropFocalX/100)*maxOffsetX:0);
frameTop=imgTop+(maxOffsetY>0?(cropFocalY/100)*maxOffsetY:0);
NT.style.setRule('crop-frame-pos','#crop-frame',
`left:${frameLeft}px;top:${frameTop}px`);}
function setFramePosition(left,top){
frameLeft=left;
frameTop=top;
NT.style.setRule('crop-frame-pos','#crop-frame',
`left:${left}px;top:${top}px`);}
function updateFocalFromFrame(){
if(!cropLayout)return;
const{imgLeft,imgTop,dispW,dispH,frameW,frameH}=cropLayout;
const maxOffsetX=dispW-frameW;
const maxOffsetY=dispH-frameH;
const relLeft=frameLeft-imgLeft;
const relTop=frameTop-imgTop;
cropFocalX=maxOffsetX>0?clamp(Math.round((relLeft/maxOffsetX)*100),0,100):50;
cropFocalY=maxOffsetY>0?clamp(Math.round((relTop/maxOffsetY)*100),0,100):50;}
let dragging=false;
let startX=0;
let startY=0;
let startFrameLeft=0;
let startFrameTop=0;
cropViewport.addEventListener('pointerdown',(e)=>{
if(!cropLayout)return;
e.preventDefault();
cropViewport.setPointerCapture(e.pointerId);
dragging=true;
startX=e.clientX;
startY=e.clientY;
startFrameLeft=frameLeft;
startFrameTop=frameTop;});
cropViewport.addEventListener('pointermove',(e)=>{
if(!dragging||!cropLayout)return;
e.preventDefault();
const{imgLeft,imgTop,dispW,dispH,frameW,frameH}=cropLayout;
const dx=e.clientX-startX;
const dy=e.clientY-startY;
const newLeft=clamp(startFrameLeft+dx,imgLeft,imgLeft+dispW-frameW);
const newTop=clamp(startFrameTop+dy,imgTop,imgTop+dispH-frameH);
setFramePosition(newLeft,newTop);
updateFocalFromFrame();});
cropViewport.addEventListener('pointerup',()=>{dragging=false;});
cropViewport.addEventListener('pointercancel',()=>{dragging=false;});
cropViewport.addEventListener('keydown',(e)=>{
const step=1;
let handled=false;
if(e.key==='ArrowLeft'){cropFocalX=clamp(cropFocalX-step,0,100);handled=true;}
if(e.key==='ArrowRight'){cropFocalX=clamp(cropFocalX+step,0,100);handled=true;}
if(e.key==='ArrowUp'){cropFocalY=clamp(cropFocalY-step,0,100);handled=true;}
if(e.key==='ArrowDown'){cropFocalY=clamp(cropFocalY+step,0,100);handled=true;}
if(handled){
e.preventDefault();
positionFrameFromFocal();}});
window.addEventListener('resize',()=>{
if(cropDialog.open)layoutCrop();});
confirmBtn.addEventListener('click',()=>{
if(onConfirmCallback){
onConfirmCallback(cropMode,{
file:cropFile,
focalX:cropFocalX,
focalY:cropFocalY,
imageId:repositionImageId,});}});
cancelBtn?.addEventListener('click',closeCropDialog);
cropDialog.addEventListener('close',()=>{
cleanupCropState();
window.scrollTo({top:savedScrollY,behavior:'instant'});
requestAnimationFrame(()=>{
window.scrollTo({top:savedScrollY,behavior:'instant'});});});
NT.crop={
openUpload(file,opts={}){
cropMode='upload';
cropFile=file;
cropFocalX=opts.focalX??50;
cropFocalY=opts.focalY??50;
repositionImageId=null;
cropObjectUrl=URL.createObjectURL(file);
cropPreview.onload=()=>layoutCrop();
cropPreview.src=cropObjectUrl;
if(confirmIcon)confirmIcon.className=opts.icon??'fa-solid fa-cloud-arrow-up';
if(cropLabelEl)cropLabelEl.textContent=opts.label??'Upload';
if(confirmBtn)confirmBtn.disabled=false;
cropDialog.dataset.mode='upload';
savedScrollY=window.scrollY;
cropDialog.showModal();
cropViewport.focus();},
openReposition(imgSrc,focalX,focalY,imageId){
cropMode='reposition';
cropFile=null;
cropObjectUrl=null;
cropFocalX=focalX;
cropFocalY=focalY;
repositionImageId=imageId;
cropPreview.onload=()=>layoutCrop();
cropPreview.src=imgSrc;
if(cropPreview.complete&&cropPreview.naturalWidth){
layoutCrop();}
if(confirmIcon)confirmIcon.className='fa-solid fa-check';
if(cropLabelEl)cropLabelEl.textContent='Save';
if(confirmBtn)confirmBtn.disabled=false;
cropDialog.dataset.mode='reposition';
savedScrollY=window.scrollY;
cropDialog.showModal();
cropViewport.focus();},
close:closeCropDialog,
onConfirm(callback){
onConfirmCallback=callback;},
setConfirmState(disabled,loading){
if(confirmBtn){
confirmBtn.disabled=disabled;
if(loading)confirmBtn.dataset.loading='';
else delete confirmBtn.dataset.loading;}},};})();
(function(){
const queue=document.getElementById('photo-queue');
const dropZone=document.getElementById('photo-drop-zone');
const fileInput=document.getElementById('tool-photos');
const dataContainer=document.getElementById('photo-queue-data');
if(!queue||!dropZone||!fileInput||!dataContainer)return;
if(document.getElementById('gallery-manager'))return;
const MAX_FILES=6;
const MAX_SIZE=5*1024*1024;
const ALLOWED_TYPES=['image/jpeg','image/png','image/webp'];
const queuedPhotos=[];
let repositionIndex=-1;
function validateFile(file){
if(!ALLOWED_TYPES.includes(file.type)){
NT.toast('Invalid file type. Use JPEG, PNG, or WebP.','error');
return false;}
if(file.size>MAX_SIZE){
NT.toast('File exceeds the 5 MB limit.','error');
return false;}
return true;}
function syncFormInputs(){
const dt=new DataTransfer();
for(const entry of queuedPhotos)dt.items.add(entry.file);
fileInput.files=dt.files;
dataContainer.innerHTML='';
for(let i=0;i<queuedPhotos.length;i++){
const xInput=document.createElement('input');
xInput.type='hidden';
xInput.name='focal_x[]';
xInput.value=String(queuedPhotos[i].focalX);
dataContainer.appendChild(xInput);
const yInput=document.createElement('input');
yInput.type='hidden';
yInput.name='focal_y[]';
yInput.value=String(queuedPhotos[i].focalY);
dataContainer.appendChild(yInput);}}
function updateHint(){
const remaining=MAX_FILES-queuedPhotos.length;
const hint=document.getElementById('photo-queue-hint');
if(hint){
hint.textContent=`JPEG, PNG, or WebP \u2014 max 5 MB each. ${remaining} slot${remaining !== 1 ? 's' : ''} remaining.`;}
dropZone.closest('div')?.toggleAttribute('hidden',remaining<=0);
if(remaining<=0)dropZone.hidden=true;
else dropZone.hidden=false;}
function renderQueue(){
for(const img of queue.querySelectorAll('img')){
if(img.src.startsWith('blob:'))URL.revokeObjectURL(img.src);}
queue.innerHTML='';
if(queuedPhotos.length===0){
queue.hidden=true;
syncFormInputs();
updateHint();
return;}
queue.hidden=false;
for(let i=0;i<queuedPhotos.length;i++){
const entry=queuedPhotos[i];
const li=document.createElement('li');
li.dataset.queueIndex=String(i);
li.draggable=true;
li.tabIndex=0;
const blobUrl=URL.createObjectURL(entry.file);
const focalX=entry.focalX;
const focalY=entry.focalY;
const focalAttrs=(focalX!==50||focalY!==50)
?` data-focal-x="${focalX}" data-focal-y="${focalY}"`:'';
li.innerHTML=`
        <img src="${blobUrl}"
             alt="Preview of ${entry.file.name}"
             width="400" height="268"
             decoding="async"${focalAttrs}>
        <div>
          <button type="button"
                  data-reposition-queue="${i}"
                  aria-label="Reposition this photo">
            <i class="fa-solid fa-crop-simple" aria-hidden="true"></i> Reposition
          </button>
        </div>
        <div>
          <button type="button"
                  data-remove-queue="${i}"
                  data-intent="danger"
                  aria-label="Remove this photo">
            <i class="fa-solid fa-trash-can" aria-hidden="true"></i> Remove
          </button>
        </div>
      `;
queue.appendChild(li);
NT.applyFocalPoints(li);}
syncFormInputs();
updateHint();}
queue.addEventListener('click',(e)=>{
const removeBtn=e.target.closest('[data-remove-queue]');
if(removeBtn){
const idx=parseInt(removeBtn.dataset.removeQueue,10);
queuedPhotos.splice(idx,1);
renderQueue();
return;}
const repoBtn=e.target.closest('[data-reposition-queue]');
if(repoBtn&&NT.crop){
repositionIndex=parseInt(repoBtn.dataset.repositionQueue,10);
const entry=queuedPhotos[repositionIndex];
const blobUrl=URL.createObjectURL(entry.file);
NT.crop.openReposition(blobUrl,entry.focalX,entry.focalY,`queue-${repositionIndex}`);}});
let dragItem=null;
queue.addEventListener('dragstart',(e)=>{
if(e.target.closest('button')){e.preventDefault();return;}
const li=e.target.closest('li[data-queue-index]');
if(!li)return;
dragItem=li;
li.dataset.dragging='';
e.dataTransfer.effectAllowed='move';
e.dataTransfer.setData('text/plain',li.dataset.queueIndex);});
queue.addEventListener('dragend',(e)=>{
const li=e.target.closest('li[data-queue-index]');
if(li)delete li.dataset.dragging;
dragItem=null;
for(const el of queue.querySelectorAll('[data-drag-over]')){
delete el.dataset.dragOver;}});
queue.addEventListener('dragover',(e)=>{
e.preventDefault();
e.dataTransfer.dropEffect='move';
const target=e.target.closest('li[data-queue-index]');
if(!target||target===dragItem)return;
for(const el of queue.querySelectorAll('[data-drag-over]')){
delete el.dataset.dragOver;}
target.dataset.dragOver='';});
queue.addEventListener('drop',(e)=>{
e.preventDefault();
const target=e.target.closest('li[data-queue-index]');
if(!target||!dragItem||target===dragItem)return;
for(const el of queue.querySelectorAll('[data-drag-over]')){
delete el.dataset.dragOver;}
const fromIdx=parseInt(dragItem.dataset.queueIndex,10);
const toIdx=parseInt(target.dataset.queueIndex,10);
const[moved]=queuedPhotos.splice(fromIdx,1);
queuedPhotos.splice(toIdx,0,moved);
renderQueue();});
queue.addEventListener('keydown',(e)=>{
const li=e.target.closest('li[data-queue-index]');
if(!li||e.target!==li)return;
const items=Array.from(queue.querySelectorAll('li[data-queue-index]'));
const idx=items.indexOf(li);
if(idx<0)return;
if((e.key==='ArrowUp'||e.key==='ArrowLeft')&&idx>0){
e.preventDefault();
const[moved]=queuedPhotos.splice(idx,1);
queuedPhotos.splice(idx-1,0,moved);
renderQueue();
queue.querySelectorAll('li[data-queue-index]')[idx-1]?.focus();}else if((e.key==='ArrowDown'||e.key==='ArrowRight')&&idx<items.length-1){
e.preventDefault();
const[moved]=queuedPhotos.splice(idx,1);
queuedPhotos.splice(idx+1,0,moved);
renderQueue();
queue.querySelectorAll('li[data-queue-index]')[idx+1]?.focus();}});
if(NT.crop){
NT.crop.onConfirm((mode,data)=>{
if(mode==='upload'){
queuedPhotos.push({file:data.file,focalX:data.focalX,focalY:data.focalY});
NT.crop.close();
renderQueue();
const lastLi=queue.querySelector('li:last-child');
lastLi?.focus({preventScroll:true});
requestAnimationFrame(()=>{
lastLi?.scrollIntoView({behavior:'smooth',block:'nearest'});});}else if(mode==='reposition'&&repositionIndex>=0){
queuedPhotos[repositionIndex].focalX=data.focalX;
queuedPhotos[repositionIndex].focalY=data.focalY;
NT.crop.close();
renderQueue();
queue.querySelectorAll('li[data-queue-index]')[repositionIndex]?.focus();
repositionIndex=-1;}});}
dropZone.setAttribute('role','button');
dropZone.tabIndex=0;
dropZone.setAttribute('aria-label','Choose a photo to upload');
dropZone.addEventListener('click',(e)=>{
if(e.target===fileInput)return;
fileInput.click();});
dropZone.addEventListener('keydown',(e)=>{
if(e.key==='Enter'||e.key===' '){
e.preventDefault();
fileInput.click();}});
fileInput.addEventListener('change',()=>{
const file=fileInput.files?.[0];
if(!file)return;
if(queuedPhotos.length>=MAX_FILES){
NT.toast(`You can upload at most ${MAX_FILES} photos.`,'error');
fileInput.value='';
return;}
if(!validateFile(file)){fileInput.value='';return;}
if(NT.crop){
NT.crop.openUpload(file,{icon:'fa-solid fa-plus',label:'Add'});}});
let dragCounter=0;
dropZone.addEventListener('dragenter',(e)=>{
e.preventDefault();
dragCounter++;
dropZone.dataset.dragover='';});
dropZone.addEventListener('dragover',(e)=>{
e.preventDefault();
e.dataTransfer.dropEffect='copy';});
dropZone.addEventListener('dragleave',()=>{
dragCounter--;
if(dragCounter<=0){
dragCounter=0;
delete dropZone.dataset.dragover;}});
dropZone.addEventListener('drop',(e)=>{
e.preventDefault();
dragCounter=0;
delete dropZone.dataset.dragover;
const file=Array.from(e.dataTransfer.files).find(f=>ALLOWED_TYPES.includes(f.type));
if(!file){
NT.toast('No valid image file found. Use JPEG, PNG, or WebP.','error');
return;}
if(queuedPhotos.length>=MAX_FILES){
NT.toast(`You can upload at most ${MAX_FILES} photos.`,'error');
return;}
if(!validateFile(file))return;
if(NT.crop){
NT.crop.openUpload(file,{icon:'fa-solid fa-plus',label:'Add'});}});
const createForm=fileInput.closest('form');
if(createForm){
createForm.addEventListener('submit',()=>syncFormInputs());}
updateHint();})();
(function(){
let gallery=document.getElementById('gallery-manager');
const fieldset=gallery?.closest('fieldset')??document.querySelector('section[aria-labelledby="edit-tool-heading"] > fieldset:last-of-type');
if(!fieldset)return;
const toolId=gallery?.dataset.toolId??document.getElementById('add-photo')?.dataset.toolId;
if(!toolId)return;
const ALLOWED_TYPES=['image/jpeg','image/png','image/webp'];
const MAX_SIZE=5*1024*1024;
let busy=false;
function getGallery(){
return document.getElementById('gallery-manager');}
function setBusy(state){
busy=state;
const g=getGallery();
if(g)g.ariaBusy=state?'true':'false';}
function getImageIds(){
const g=getGallery();
if(!g)return[];
return Array.from(g.querySelectorAll('li[data-image-id]'))
.map(li=>parseInt(li.dataset.imageId,10));}
function escapeAttr(str){
const div=document.createElement('div');
div.appendChild(document.createTextNode(str));
return div.innerHTML.replace(/"/g,'&quot;');}
function ensureGallery(){
let g=getGallery();
if(g)return g;
const emptyMsg=fieldset.querySelector('#gallery-empty');
if(emptyMsg)emptyMsg.remove();
g=document.createElement('ol');
g.id='gallery-manager';
g.setAttribute('aria-label','Tool photos');
g.dataset.toolId=toolId;
const hint=fieldset.querySelector('#gallery-crop-hint');
if(hint){
hint.after(g);}else{
fieldset.querySelector('legend').after(g);}
attachGalleryListeners(g);
gallery=g;
return g;}
function updateSlotHint(){
const g=getGallery();
const remaining=6-(g?g.querySelectorAll('li[data-image-id]').length:0);
const uploadForm=document.getElementById('photo-upload-form');
if(uploadForm){
uploadForm.hidden=remaining<=0;
const hint=document.getElementById('add-photo-hint');
if(hint&&remaining>0){
hint.textContent=`JPEG, PNG, or WebP \u2014 max 5 MB. ${remaining} slot${remaining !== 1 ? 's' : ''} remaining.`;}}}
function validateFile(file){
if(!ALLOWED_TYPES.includes(file.type)){
NT.toast('Invalid file type. Use JPEG, PNG, or WebP.','error');
return false;}
if(file.size>MAX_SIZE){
NT.toast('File exceeds the 5 MB limit.','error');
return false;}
return true;}
function buildLiHtml(img){
const thumb=escapeAttr(img.filename.replace(/\.(\w+)$/,'-400w.$1'));
const altSafe=escapeAttr(img.alt_text||'');
const csrfToken=escapeAttr(document.querySelector('meta[name="csrf-token"]')?.content??'');
const fx=img.focal_x??50;
const fy=img.focal_y??50;
const focalAttrs=(fx!==50||fy!==50)?` data-focal-x="${fx}" data-focal-y="${fy}"`:'';
return`
      <img src="/uploads/tools/${thumb}"
           alt="${altSafe}"
           width="400" height="268"
           loading="lazy"
           decoding="async"${focalAttrs}>
      <div>
        <label for="alt-text-${img.id}">
          <span class="visually-hidden">Alt text for image ${img.id}</span>
        </label>
        <input type="text"
               id="alt-text-${img.id}"
               value=""
               maxlength="255"
               placeholder="Describe this photo\u2026"
               data-alt-input
               data-image-id="${img.id}">
      </div>
      <div>
        <input type="radio"
               name="primary_image"
               id="primary-${img.id}"
               value="${img.id}"
               ${img.is_primary ? 'checked' : ''}
               data-primary-radio>
        <label for="primary-${img.id}">
          ${img.is_primary ? '<i class="fa-solid fa-star" aria-hidden="true"></i> ' : ''}Primary
        </label>
      </div>
      <div>
        <button type="button"
                data-reposition
                data-image-id="${img.id}"
                aria-label="Reposition this photo">
          <i class="fa-solid fa-crop-simple" aria-hidden="true"></i> Reposition
        </button>
      </div>
      <form method="post" action="/tools/${toolId}/images/${img.id}" data-delete-form>
        <input type="hidden" name="_method" value="DELETE">
        <input type="hidden" name="csrf_token" value="${csrfToken}">
        <button type="submit" data-intent="danger" aria-label="Delete this photo">
          <i class="fa-solid fa-trash-can" aria-hidden="true"></i> Delete
        </button>
      </form>
    `;}
async function persistOrder(){
try{
const res=await NT.fetch(`/tools/${toolId}/images/order`,{
method:'PATCH',
body:JSON.stringify({order:getImageIds()}),});
if(!res.ok){
NT.toast('Failed to save new order.','error');
return false;}
return true;}catch{
NT.toast('Failed to save new order.','error');
return false;}}
if(NT.crop){
NT.crop.onConfirm(async(mode,data)=>{
if(busy)return;
if(mode==='upload'){
if(!data.file)return;
NT.crop.setConfirmState(true,true);
setBusy(true);
const fd=new FormData();
fd.append('photo',data.file);
fd.append('focal_x',String(data.focalX));
fd.append('focal_y',String(data.focalY));
try{
const res=await NT.fetch(`/tools/${toolId}/images`,{
method:'POST',
body:fd,});
if(!res.ok){
const err=await res.json().catch(()=>null);
NT.toast(err?.error??'Failed to upload photo.','error');
NT.crop.setConfirmState(false,false);
setBusy(false);
return;}
const img=await res.json();
const g=ensureGallery();
const li=document.createElement('li');
li.dataset.imageId=img.id;
li.dataset.focalX=String(img.focal_x??data.focalX);
li.dataset.focalY=String(img.focal_y??data.focalY);
li.draggable=true;
li.tabIndex=0;
li.innerHTML=buildLiHtml(img);
g.appendChild(li);
NT.applyFocalPoints(li);
NT.crop.close();
updateSlotHint();
li.focus({preventScroll:true});
requestAnimationFrame(()=>{
li.scrollIntoView({behavior:'smooth',block:'nearest'});});
NT.toast('Photo uploaded.','success');}catch{
NT.toast('Failed to upload photo.','error');
NT.crop.setConfirmState(false,false);}finally{
setBusy(false);}}else if(mode==='reposition'){
if(!data.imageId)return;
NT.crop.setConfirmState(true,true);
setBusy(true);
try{
const res=await NT.fetch(`/tools/${toolId}/images/${data.imageId}`,{
method:'PATCH',
body:JSON.stringify({focal_x:data.focalX,focal_y:data.focalY}),});
if(!res.ok){
NT.toast('Failed to save position.','error');
NT.crop.setConfirmState(false,false);
setBusy(false);
return;}
const g=getGallery();
const li=g?.querySelector(`li[data-image-id="${data.imageId}"]`);
if(li){
li.dataset.focalX=String(data.focalX);
li.dataset.focalY=String(data.focalY);
const img=li.querySelector('img');
if(img){
if(data.focalX!==50||data.focalY!==50){
img.dataset.focalX=String(data.focalX);
img.dataset.focalY=String(data.focalY);}else{
delete img.dataset.focalX;
delete img.dataset.focalY;}
NT.applyFocalPoints(li);}}
NT.crop.close();
NT.toast('Position saved.','success');}catch{
NT.toast('Failed to save position.','error');
NT.crop.setConfirmState(false,false);}finally{
setBusy(false);}}});}
let dragItem=null;
function attachGalleryListeners(g){
g.addEventListener('dragstart',(e)=>{
if(e.target.closest('input, button, label, a')){
e.preventDefault();
return;}
const li=e.target.closest('li[data-image-id]');
if(!li)return;
dragItem=li;
li.dataset.dragging='';
e.dataTransfer.effectAllowed='move';
e.dataTransfer.setData('text/plain',li.dataset.imageId);});
g.addEventListener('dragend',(e)=>{
const li=e.target.closest('li[data-image-id]');
if(li)delete li.dataset.dragging;
dragItem=null;
for(const el of g.querySelectorAll('[data-drag-over]')){
delete el.dataset.dragOver;}});
g.addEventListener('dragover',(e)=>{
e.preventDefault();
e.dataTransfer.dropEffect='move';
const target=e.target.closest('li[data-image-id]');
if(!target||target===dragItem)return;
for(const el of g.querySelectorAll('[data-drag-over]')){
delete el.dataset.dragOver;}
target.dataset.dragOver='';});
g.addEventListener('drop',async(e)=>{
e.preventDefault();
const target=e.target.closest('li[data-image-id]');
if(!target||!dragItem||target===dragItem||busy)return;
for(const el of g.querySelectorAll('[data-drag-over]')){
delete el.dataset.dragOver;}
const items=Array.from(g.querySelectorAll('li[data-image-id]'));
const dragIdx=items.indexOf(dragItem);
const targetIdx=items.indexOf(target);
const refNode=dragItem.nextElementSibling;
if(dragIdx<targetIdx){
target.after(dragItem);}else{
target.before(dragItem);}
setBusy(true);
const ok=await persistOrder();
if(!ok){
if(refNode)refNode.before(dragItem);
else g.appendChild(dragItem);}
setBusy(false);});
g.addEventListener('keydown',async(e)=>{
if(e.target!==e.target.closest('li[data-image-id]'))return;
const li=e.target;
if(!li||busy)return;
const items=Array.from(g.querySelectorAll('li[data-image-id]'));
const idx=items.indexOf(li);
if(idx<0)return;
let swapTarget=null;
if((e.key==='ArrowUp'||e.key==='ArrowLeft')&&idx>0){
swapTarget=items[idx-1];
e.preventDefault();
swapTarget.before(li);}else if((e.key==='ArrowDown'||e.key==='ArrowRight')&&idx<items.length-1){
swapTarget=items[idx+1];
e.preventDefault();
swapTarget.after(li);}
if(!swapTarget)return;
li.focus();
setBusy(true);
const ok=await persistOrder();
if(!ok){
if(e.key==='ArrowUp'||e.key==='ArrowLeft'){
swapTarget.after(li);}else{
swapTarget.before(li);}
li.focus();}
setBusy(false);});
g.addEventListener('click',async(e)=>{
const deleteBtn=e.target.closest('[data-delete-form] button[type="submit"]');
if(!deleteBtn)return;
e.preventDefault();
if(busy)return;
const li=deleteBtn.closest('li[data-image-id]');
if(!li)return;
const imageId=li.dataset.imageId;
if(!await NT.confirm('Delete this photo?'))return;
setBusy(true);
deleteBtn.disabled=true;
try{
const res=await NT.fetch(`/tools/${toolId}/images/${imageId}`,{
method:'DELETE',});
if(!res.ok){
NT.toast('Failed to delete photo.','error');
deleteBtn.disabled=false;
setBusy(false);
return;}
const data=await res.json();
li.remove();
if(data.new_primary_id){
const promoted=g.querySelector(`li[data-image-id="${data.new_primary_id}"] [data-primary-radio]`);
if(promoted){
promoted.checked=true;
const label=promoted.nextElementSibling;
if(label)label.innerHTML='<i class="fa-solid fa-star" aria-hidden="true"></i> Primary';}}
const remaining=g.querySelectorAll('li[data-image-id]').length;
if(remaining===0){
g.remove();
const empty=document.createElement('p');
empty.id='gallery-empty';
empty.textContent='No photos uploaded yet.';
const hint=fieldset.querySelector('#gallery-crop-hint');
if(hint){
hint.after(empty);}else{
fieldset.querySelector('legend').after(empty);}}
updateSlotHint();
NT.toast('Photo deleted.','success');}catch{
NT.toast('Failed to delete photo.','error');
deleteBtn.disabled=false;}finally{
setBusy(false);}});
g.addEventListener('change',async(e)=>{
const radio=e.target.closest('[data-primary-radio]');
if(!radio||busy)return;
const imageId=radio.value;
setBusy(true);
for(const r of g.querySelectorAll('[data-primary-radio]')){
r.disabled=true;}
try{
const res=await NT.fetch(`/tools/${toolId}/images/${imageId}/primary`,{
method:'PATCH',});
if(!res.ok){
NT.toast('Failed to set primary photo.','error');
setBusy(false);
return;}
for(const li of g.querySelectorAll('li[data-image-id]')){
const r=li.querySelector('[data-primary-radio]');
const label=r?.nextElementSibling;
if(!label)continue;
if(r.value===imageId){
label.innerHTML='<i class="fa-solid fa-star" aria-hidden="true"></i> Primary';}else{
label.textContent='Primary';}}
NT.toast('Primary photo updated.','success');}catch{
NT.toast('Failed to set primary photo.','error');}finally{
for(const r of g.querySelectorAll('[data-primary-radio]')){
r.disabled=false;}
setBusy(false);}});
g.addEventListener('click',(e)=>{
const btn=e.target.closest('[data-reposition]');
if(!btn||busy)return;
const li=btn.closest('li[data-image-id]');
if(!li)return;
const imageId=li.dataset.imageId;
const img=li.querySelector('img');
if(!img)return;
const fx=parseInt(li.dataset.focalX??'50',10);
const fy=parseInt(li.dataset.focalY??'50',10);
NT.crop?.openReposition(img.src,fx,fy,imageId);});
g.addEventListener('blur',async(e)=>{
const input=e.target.closest('[data-alt-input]');
if(!input||busy)return;
const imageId=input.dataset.imageId;
const altText=input.value.trim().slice(0,255);
try{
const res=await NT.fetch(`/tools/${toolId}/images/${imageId}`,{
method:'PATCH',
body:JSON.stringify({alt_text:altText}),});
if(res.ok){
NT.toast('Alt text saved.','success');}else{
NT.toast('Failed to save alt text.','error');}}catch{
NT.toast('Failed to save alt text.','error');}},true);}
if(gallery){
attachGalleryListeners(gallery);}
const dropZone=document.getElementById('photo-drop-zone');
const fileInput=document.getElementById('add-photo');
if(dropZone&&fileInput){
dropZone.setAttribute('role','button');
dropZone.tabIndex=0;
dropZone.setAttribute('aria-label','Choose a photo to upload');
dropZone.addEventListener('click',(e)=>{
if(e.target===fileInput)return;
fileInput.click();});
dropZone.addEventListener('keydown',(e)=>{
if(e.key==='Enter'||e.key===' '){
e.preventDefault();
fileInput.click();}});
fileInput.addEventListener('change',()=>{
const file=fileInput.files?.[0];
if(!file)return;
if(!validateFile(file)){fileInput.value='';return;}
NT.crop?.openUpload(file);});
let dragCounter=0;
dropZone.addEventListener('dragenter',(e)=>{
e.preventDefault();
dragCounter++;
dropZone.dataset.dragover='';});
dropZone.addEventListener('dragover',(e)=>{
e.preventDefault();
e.dataTransfer.dropEffect='copy';});
dropZone.addEventListener('dragleave',()=>{
dragCounter--;
if(dragCounter<=0){
dragCounter=0;
delete dropZone.dataset.dragover;}});
dropZone.addEventListener('drop',(e)=>{
e.preventDefault();
dragCounter=0;
delete dropZone.dataset.dragover;
const file=Array.from(e.dataTransfer.files).find(f=>ALLOWED_TYPES.includes(f.type));
if(!file){
NT.toast('No valid image file found. Use JPEG, PNG, or WebP.','error');
return;}
if(!validateFile(file))return;
NT.crop?.openUpload(file);});}})();
(function(){
const galleryEl=document.getElementById('tool-gallery');
if(!galleryEl)return;
const mainFigure=document.getElementById('gallery-main');
const mainImg=document.getElementById('gallery-main-img');
const mainSource=document.getElementById('gallery-main-source');
const thumbList=document.getElementById('gallery-thumbs');
const lightbox=document.getElementById('gallery-lightbox');
const lightboxImg=document.getElementById('lightbox-img');
const prevBtn=document.getElementById('lightbox-prev');
const nextBtn=document.getElementById('lightbox-next');
const closeBtn=document.getElementById('lightbox-close');
if(thumbList&&mainImg){
const thumbButtons=thumbList.querySelectorAll('button');
let currentIndex=0;
function setActiveThumb(index){
currentIndex=index;
for(let i=0;i<thumbButtons.length;i++){
thumbButtons[i].setAttribute('aria-current',i===index?'true':'false');}
const btn=thumbButtons[index];
if(!btn)return;
mainImg.src=btn.dataset.full;
mainImg.srcset=btn.dataset.srcset||'';
mainImg.alt=btn.dataset.alt||'';
if(mainSource){
const webpSrcset=btn.dataset.srcsetWebp;
if(webpSrcset){
mainSource.srcset=webpSrcset;
mainSource.hidden=false;}else{
mainSource.srcset='';
mainSource.hidden=true;}}
const fx=btn.dataset.focalX??'50';
const fy=btn.dataset.focalY??'50';
if(fx!=='50'||fy!=='50'){
mainImg.dataset.focalX=fx;
mainImg.dataset.focalY=fy;}else{
delete mainImg.dataset.focalX;
delete mainImg.dataset.focalY;}
NT.applyFocalPoints(mainImg);
const link=mainImg.closest('a[data-lightbox-trigger]');
if(link)link.href=btn.dataset.full;
const caption=mainFigure?.querySelector('figcaption');
const altText=btn.dataset.alt||'';
if(caption){
caption.textContent=altText;
caption.hidden=altText==='';}}
thumbList.addEventListener('click',(e)=>{
const btn=e.target.closest('button');
if(!btn)return;
const index=Array.from(thumbButtons).indexOf(btn);
if(index>=0)setActiveThumb(index);});
galleryEl.addEventListener('keydown',(e)=>{
if(lightbox?.open)return;
if(e.key==='ArrowRight'||e.key==='ArrowDown'){
e.preventDefault();
setActiveThumb((currentIndex+1)%thumbButtons.length);}else if(e.key==='ArrowLeft'||e.key==='ArrowUp'){
e.preventDefault();
setActiveThumb((currentIndex-1+thumbButtons.length)%thumbButtons.length);}});}
if(!lightbox||!lightboxImg)return;
const allImages=[];
let lightboxIndex=0;
let triggerElement=null;
if(thumbList){
for(const btn of thumbList.querySelectorAll('button')){
allImages.push({
src:btn.dataset.full,
alt:btn.dataset.alt||'',});}}else if(mainImg){
const link=mainImg.closest('a[data-lightbox-trigger]');
allImages.push({
src:link?.href||mainImg.src,
alt:mainImg.alt,});}
function showLightboxImage(index){
lightboxIndex=index;
const img=allImages[index];
if(!img)return;
lightboxImg.src=img.src;
lightboxImg.alt=img.alt;
if(prevBtn)prevBtn.hidden=allImages.length<=1;
if(nextBtn)nextBtn.hidden=allImages.length<=1;}
function openLightbox(index){
triggerElement=document.activeElement;
showLightboxImage(index);
lightbox.showModal();}
function closeLightbox(){
lightbox.close();
triggerElement?.focus();
triggerElement=null;}
galleryEl.addEventListener('click',(e)=>{
const trigger=e.target.closest('[data-lightbox-trigger]');
if(!trigger)return;
e.preventDefault();
let index=0;
if(thumbList){
const activeBtn=thumbList.querySelector('button[aria-current="true"]');
if(activeBtn){
index=Array.from(thumbList.querySelectorAll('button')).indexOf(activeBtn);}}
openLightbox(Math.max(0,index));});
closeBtn?.addEventListener('click',closeLightbox);
lightbox.addEventListener('click',(e)=>{
if(e.target===lightbox)closeLightbox();});
prevBtn?.addEventListener('click',()=>{
showLightboxImage((lightboxIndex-1+allImages.length)%allImages.length);});
nextBtn?.addEventListener('click',()=>{
showLightboxImage((lightboxIndex+1)%allImages.length);});
lightbox.addEventListener('keydown',(e)=>{
if(e.key==='Escape'){
e.preventDefault();
closeLightbox();}else if(e.key==='ArrowLeft'&&allImages.length>1){
e.preventDefault();
showLightboxImage((lightboxIndex-1+allImages.length)%allImages.length);}else if(e.key==='ArrowRight'&&allImages.length>1){
e.preventDefault();
showLightboxImage((lightboxIndex+1)%allImages.length);}});})();